import{f as a,o as e,c as d,a2 as r}from"./chunks/framework.DHYrF-q6.js";const u=JSON.parse('{"title":"移动端与跨平台","description":"","frontmatter":{},"headers":[],"relativePath":"frontend/mobile/index.md","filePath":"frontend/mobile/index.md","lastUpdated":1780903801000}'),i={name:"frontend/mobile/index.md"};function l(o,t,h,n,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="移动端与跨平台" tabindex="-1">移动端与跨平台 <a class="header-anchor" href="#移动端与跨平台" aria-label="Permalink to &quot;移动端与跨平台&quot;">​</a></h1><h2 id="⭐-面试重点速览" tabindex="-1">⭐ 面试重点速览 <a class="header-anchor" href="#⭐-面试重点速览" aria-label="Permalink to &quot;⭐ 面试重点速览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识模块</th><th>重点内容</th><th>面试频率</th></tr></thead><tbody><tr><td>微信小程序</td><td>双线程架构、setData 原理与优化、生命周期</td><td>中高</td></tr><tr><td>React Native</td><td>JS Bridge 通信、Virtual DOM→Native 组件、新旧架构对比</td><td>中</td></tr><tr><td>Flutter</td><td>Skia 自绘引擎、Dart 语言、与 RN 对比</td><td>中</td></tr><tr><td>Taro / uni-app</td><td>编译时转换、多端适配、条件编译</td><td>中高</td></tr><tr><td>跨端框架对比</td><td>渲染方式/性能/生态/学习成本/适用场景</td><td>中</td></tr></tbody></table><hr><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>移动端与跨平台开发是前端工程师的重要技能延伸。随着小程序生态的繁荣和跨端框架的成熟，高级前端工程师需要了解不同平台的技术原理和选型策略，以应对多样化的业务需求。</p><div class="tip custom-block"><p class="custom-block-title">适用人群</p><p>准备中大厂面试的前端工程师，特别是涉及小程序、跨端开发岗位的候选人。</p></div><h2 id="子模块简介" tabindex="-1">子模块简介 <a class="header-anchor" href="#子模块简介" aria-label="Permalink to &quot;子模块简介&quot;">​</a></h2><table tabindex="0"><thead><tr><th>子模块</th><th>定位</th><th>核心难点</th><th>课时建议</th></tr></thead><tbody><tr><td><a href="./wechat-miniprogram">微信小程序核心原理</a></td><td>小程序底层机制</td><td>双线程架构、setData 性能优化</td><td>1~2 天</td></tr><tr><td><a href="./cross-platform">跨端框架原理对比</a></td><td>跨端技术选型</td><td>RN/Flutter/Taro/uni-app 架构差异</td><td>1~2 天</td></tr></tbody></table><hr><h2 id="学习建议" tabindex="-1">学习建议 <a class="header-anchor" href="#学习建议" aria-label="Permalink to &quot;学习建议&quot;">​</a></h2><ol><li>优先掌握微信小程序核心原理（双线程架构 + setData 优化），这是国内面试最常见的移动端考点</li><li>了解 React Native 和 Flutter 的基本原理和区别，能说清楚选型理由</li><li>Taro/uni-app 关注编译时转换思路，理解多端适配的本质</li></ol><div class="danger custom-block"><p class="custom-block-title">容易翻车的点</p><ul><li>不知道微信小程序的双线程架构设计</li><li>分不清 React Native 和 Flutter 的渲染方式区别</li><li>认为 Taro 是运行时跨端（实际是编译时）</li></ul></div>',13)])])}const b=a(i,[["render",l]]);export{u as __pageData,b as default};
